function validate(args, output) {
    const preorder = args[0], postorder = args[1];
    function deser(a) {
        if (!a || a.length === 0) return null;
        const nodes = [[a[0], null, null]];
        let idx = 1, i = 0;
        while (i < nodes.length && idx < a.length) {
            const node = nodes[i];
            if (idx < a.length) {
                const v = a[idx]; idx++;
                if (v !== null) { node[1] = nodes.length; nodes.push([v, null, null]); }
            }
            if (idx < a.length) {
                const v = a[idx]; idx++;
                if (v !== null) { node[2] = nodes.length; nodes.push([v, null, null]); }
            }
            i++;
        }
        return nodes;
    }
    const nodes = deser(output);
    if (nodes === null) return preorder.length === 0;
    function pre(i, acc) {
        if (i === null) return;
        const [val, l, r] = nodes[i];
        acc.push(val); pre(l, acc); pre(r, acc);
    }
    function post(i, acc) {
        if (i === null) return;
        const [val, l, r] = nodes[i];
        post(l, acc); post(r, acc); acc.push(val);
    }
    const preAcc = []; pre(0, preAcc);
    const postAcc = []; post(0, postAcc);
    if (preAcc.length !== preorder.length || postAcc.length !== postorder.length) return false;
    for (let k = 0; k < preAcc.length; k++) if (preAcc[k] !== preorder[k]) return false;
    for (let k = 0; k < postAcc.length; k++) if (postAcc[k] !== postorder[k]) return false;
    return true;
}

