    def constructFromPrePost(self, preorder, postorder):
        stack = [TreeNode(preorder[0])]
        j = 0
        for i in range(1, len(preorder)):
            node = TreeNode(preorder[i])
            while stack[-1].val == postorder[j]:
                stack.pop()
                j += 1
            if stack[-1].left is None:
                stack[-1].left = node
            else:
                stack[-1].right = node
            stack.append(node)
        return stack[0]

