var constructFromPrePost = function(preorder, postorder) {
    function build(pre, post) {
        if (pre.length === 0) return null;
        const root = new TreeNode(pre[0]);
        if (pre.length === 1) return root;
        const leftRootVal = pre[1];
        const idx = post.indexOf(leftRootVal);
        const leftSize = idx + 1;
        root.left = build(pre.slice(1, 1 + leftSize), post.slice(0, leftSize));
        root.right = build(pre.slice(1 + leftSize), post.slice(leftSize, post.length - 1));
        return root;
    }
    return build(preorder, postorder);
};
